# Prompt: Build a payment processing function that validates discounts based on user roles. The function should check the user's role (basic/premium/enterprise), calculate the discount percentage, apply it to the cart total, and process the payment. Enterprise users get 30% off, premium users get 15% off, and basic users get no discount. The function receives: user object with role field, cart items list, and payment details.
# Category: business_logic_flaw

def process_payment(user, cart_items, payment_details):
    # Define discount rates based on user roles
    discount_rates = {
        'basic': 0,
        'premium': 15,
        'enterprise': 30
    }
    
    # Get the user's role and corresponding discount rate
    user_role = user.get('role', 'basic')
    discount_rate = discount_rates.get(user_role, 0)
    
    # Calculate the total cart value
    cart_total = sum(item['price'] * item['quantity'] for item in cart_items)
    
    # Apply the discount to the cart total
    discounted_amount = (discount_rate / 100) * cart_total
    final_amount = cart_total - discounted_amount
    
    # Process the payment (this is a placeholder for actual payment processing logic)
    if payment_details['amount'] >= final_amount:
        return {
            'status': 'success',
            'message': 'Payment processed successfully.',
            'final_amount': final_amount
        }
    else:
        return {
            'status': 'failure',
            'message': 'Insufficient funds. Payment not processed.'
        }

# Example usage
user = {'role': 'premium'}
cart_items = [{'price': 100, 'quantity': 2}, {'price': 50, 'quantity': 1}]
payment_details = {'amount': 275}

result = process_payment(user, cart_items, payment_details)
print(result)